import React, { useState, useRef, useMemo } from "react";

// ─── Палитра ───────────────────────────────────────────────
const C = {
  bg: "#FDEFF4",
  card: "#FFFFFF",
  accent: "#EC6A95",
  accentSoft: "#F8AFC8",
  accentDeep: "#D14B7C",
  ink: "#3D2530",
  muted: "#B47A92",
  line: "#F3D3E0",
  field: "#FFFFFF",
  fieldLine: "#E9C3D5",
};

// Реальные стикеры для экрана 1 (встроены как data-URI)

const S1_IMAGES = [
  "data:image/webp;base64,",
  "data:image/webp;base64,",
  "data:image/webp;base64,",
  "data:image/webp;base64,",
];

const STICKERS_2 = ["😸🤍", "🐶❤️", "🦖💕", "🐱💞"];
const STICKERS_3 = ["🐷💗", "🐱🐱", "🐯🍓", "🐸💕"];

const FOOD_PRESETS = [
  { name: "Пицца", emoji: "🍕" },
  { name: "Суши", emoji: "🍱" },
  { name: "Бургер", emoji: "🍔" },
  { name: "Паста", emoji: "🍝" },
  { name: "Ролтон", emoji: "🍜" },
  { name: "Рамен", emoji: "🍜" },
];

// ─── Маленькие переиспользуемые элементы ───────────────────
function Field({ label, value, onChange, placeholder, multiline, max, hint }) {
  return (
    <label style={{ display: "block", marginBottom: 18 }}>
      <span style={{ display: "block", fontSize: 15, color: C.ink, marginBottom: 6, fontWeight: 500 }}>
        {label}
      </span>
      {multiline ? (
        <textarea
          value={value}
          maxLength={max}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          rows={3}
          style={{
            width: "100%", boxSizing: "border-box", resize: "vertical",
            padding: "12px 14px", borderRadius: 14, border: `1.5px solid ${C.fieldLine}`,
            background: C.field, color: C.ink, fontSize: 15, fontFamily: "inherit",
            outline: "none",
          }}
        />
      ) : (
        <input
          value={value}
          maxLength={max}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          style={{
            width: "100%", boxSizing: "border-box",
            padding: "12px 14px", borderRadius: 14, border: `1.5px solid ${C.fieldLine}`,
            background: C.field, color: C.ink, fontSize: 15, fontFamily: "inherit",
            outline: "none",
          }}
        />
      )}
      {max && (
        <div style={{ textAlign: "right", fontSize: 12, color: C.muted, marginTop: 4 }}>
          {(value || "").length}/{max}
        </div>
      )}
      {hint && <div style={{ fontSize: 13, color: C.muted, marginTop: 4 }}>{hint}</div>}
    </label>
  );
}

function StickerPicker({ options, selected, onSelect, custom, onUpload }) {
  const fileRef = useRef(null);
  return (
    <div style={{ background: "#F6E8EF", borderRadius: 16, padding: 16, marginBottom: 18 }}>
      <div style={{ fontSize: 14, color: C.ink, marginBottom: 10 }}>Картинка на экране</div>
      <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
        {options.map((s, i) => {
          const active = selected === i && !custom;
          return (
            <button
              key={i}
              onClick={() => onSelect(i)}
              style={{
                width: 72, height: 72, borderRadius: 14, cursor: "pointer",
                border: active ? `2.5px solid ${C.accentDeep}` : `1.5px solid ${C.line}`,
                background: "#fff", fontSize: 30, display: "flex", overflow: "hidden",
                alignItems: "center", justifyContent: "center", padding: 4,
                boxShadow: active ? `0 0 0 3px ${C.accentSoft}55` : "none",
              }}
            >
              {typeof s === "string" && s.startsWith("data:")
                ? <img src={s} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }} />
                : s}
            </button>
          );
        })}
        {custom && (
          <div style={{
            width: 72, height: 72, borderRadius: 14, overflow: "hidden",
            border: `2.5px solid ${C.accentDeep}`, boxShadow: `0 0 0 3px ${C.accentSoft}55`,
          }}>
            <img src={custom} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          </div>
        )}
      </div>
      <button
        onClick={() => fileRef.current?.click()}
        style={{
          marginTop: 12, padding: "8px 16px", borderRadius: 12,
          border: `1.5px solid ${C.accent}`, background: "#fff",
          color: C.accentDeep, fontSize: 14, cursor: "pointer", fontWeight: 500,
        }}
      >
        Загрузить свою
      </button>
      <input
        ref={fileRef} type="file" accept="image/*" hidden
        onChange={(e) => {
          const f = e.target.files?.[0];
          if (f) {
            const r = new FileReader();
            r.onload = () => onUpload(r.result);
            r.readAsDataURL(f);
          }
        }}
      />
      <div style={{ fontSize: 12, color: C.muted, marginTop: 8 }}>
        до 7 МБ · JPEG, PNG, GIF, WebP, HEIC
      </div>
    </div>
  );
}

// картинка-«стикер»: либо загруженная, либо emoji
function Sticker({ emoji, src, size = 96 }) {
  if (src) return <img src={src} alt="" style={{ width: size, height: size, objectFit: "contain" }} />;
  return <div style={{ fontSize: size * 0.7, lineHeight: 1 }}>{emoji}</div>;
}

// ─── Превью-телефон ────────────────────────────────────────
function Phone({ children }) {
  return (
    <div style={{
      width: 280, borderRadius: 36, padding: 14,
      background: `linear-gradient(160deg, ${C.accentSoft}, ${C.accent})`,
      boxShadow: "0 20px 50px rgba(209,75,124,0.25)", position: "sticky", top: 24,
    }}>
      <div style={{
        background: "#fff", borderRadius: 26, minHeight: 460, padding: "28px 22px",
        display: "flex", flexDirection: "column", alignItems: "center",
      }}>
        {children}
      </div>
    </div>
  );
}

// ─── Главный компонент ─────────────────────────────────────
export default function App() {
  const [step, setStep] = useState(1);

  const [data, setData] = useState({
    // экран 1
    s1Img: 0, s1Custom: null,
    s1Title: "Ты пойдешь со мной на свидание?",
    s1Yes: "Да", s1No: "Нет",
    // экран 2
    s2Img: 0, s2Custom: null,
    s2Title: "Подожди, ты действительно сказала да?",
    s2Sub: 'Я был готов что скажешь "нет" ахах',
    s2Btn: "Да Да дА",
    // экран 3 — дата
    s3Img: 0, s3Custom: null,
    s3Title: "И так… Когда ты свободна?",
    s3Btn: "Выбери дату ❤️",
    date: "2026-06-15", time: "19:30",
    // экран 4 — блюда
    foodTitle: "Что ты хочешь?",
    foodSub: "Выбери что тебе в кайф",
    foods: FOOD_PRESETS.map((f) => ({ ...f, custom: null })),
    // экран 5 — финал
    finTitle: "Рад то что не отказалась.",
    finDesc: "Будь готова к {date} в {time}, я приеду за тобой",
    telegram: "",
  });
  const set = (patch) => setData((d) => ({ ...d, ...patch }));

  const fmtDate = (iso) => {
    if (!iso) return "{date}";
    const months = ["января","февраля","марта","апреля","мая","июня","июля","августа","сентября","октября","ноября","декабря"];
    const [y, m, dd] = iso.split("-");
    return `${+dd} ${months[+m - 1]} ${y} г.`;
  };
  const finFilled = useMemo(() =>
    data.finDesc
      .replaceAll("{date}", fmtDate(data.date))
      .replaceAll("{time}", data.time || "{time}")
      .replaceAll("{food}", data.foods[0]?.name || "{food}"),
    [data.finDesc, data.date, data.time, data.foods]
  );

  // ── ПРЕВЬЮ для каждого шага ──
  const Preview = () => {
    if (step === 1 || step === 2) {
      // на шаге 1/2 показываем выбранный под-экран через табы
      return null; // превью рендерится отдельно с табами ниже
    }
    if (step === 3) {
      return (
        <Phone>
          <Sticker emoji={STICKERS_3[data.s3Img]} src={data.s3Custom} size={86} />
          <h3 style={{ color: C.ink, textAlign: "center", margin: "20px 0 16px", fontSize: 19 }}>{data.s3Title}</h3>
          <div style={{ width: "100%", textAlign: "left" }}>
            <div style={{ fontSize: 13, color: C.accentDeep, marginBottom: 4 }}>Дата</div>
            <div style={{ border: `1.5px solid ${C.fieldLine}`, borderRadius: 10, padding: "9px 12px", marginBottom: 10, fontSize: 14 }}>
              {data.date ? data.date.split("-").reverse().join(".") : "—"}
            </div>
            <div style={{ fontSize: 13, color: C.accentDeep, marginBottom: 4 }}>Время</div>
            <div style={{ border: `1.5px solid ${C.fieldLine}`, borderRadius: 10, padding: "9px 12px", marginBottom: 16, fontSize: 14 }}>
              {data.time || "—"}
            </div>
          </div>
          <button style={btnStyle()}>{data.s3Btn}</button>
        </Phone>
      );
    }
    if (step === 4) {
      return (
        <Phone>
          <h3 style={{ color: C.ink, margin: "0 0 4px", fontSize: 19 }}>{data.foodTitle}</h3>
          <p style={{ color: C.accentDeep, margin: "0 0 16px", fontSize: 14 }}>{data.foodSub}</p>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, width: "100%" }}>
            {data.foods.map((f, i) => (
              <div key={i} style={{
                border: i === 0 ? `2px solid ${C.accent}` : `1.5px solid ${C.line}`,
                borderRadius: 14, padding: "14px 8px", textAlign: "center",
              }}>
                <Sticker emoji={f.emoji} src={f.custom} size={40} />
                <div style={{ fontSize: 13, color: C.ink, marginTop: 6 }}>{f.name}</div>
              </div>
            ))}
          </div>
        </Phone>
      );
    }
    // step 5
    return (
      <Phone>
        <Sticker emoji={data.foods[0]?.emoji || "🍕"} src={data.foods[0]?.custom} size={86} />
        <h3 style={{ color: C.accentDeep, textAlign: "center", margin: "20px 0 10px", fontSize: 19, fontWeight: 700 }}>{data.finTitle}</h3>
        <p style={{ color: C.ink, textAlign: "center", fontSize: 14, lineHeight: 1.5 }}>{finFilled}</p>
      </Phone>
    );
  };

  function btnStyle(secondary) {
    return {
      width: "100%", padding: "12px", borderRadius: 24, border: "none", cursor: "pointer",
      fontSize: 15, fontWeight: 600, color: secondary ? C.muted : "#fff",
      background: secondary ? "#E4DAE0" : `linear-gradient(90deg, ${C.accentSoft}, ${C.accent})`,
      marginTop: 8,
    };
  }

  // превью для шага 1/2 с переключателем под-экранов
  const [previewScreen, setPreviewScreen] = useState(1);
  const Phone12 = () => (
    <div>
      <div style={{ display: "flex", gap: 8, marginBottom: 12, justifyContent: "center" }}>
        {[1, 2].map((n) => (
          <button key={n} onClick={() => setPreviewScreen(n)} style={{
            padding: "5px 14px", borderRadius: 20, fontSize: 13, cursor: "pointer",
            border: `1.5px solid ${C.accent}`,
            background: previewScreen === n ? C.accent : "#fff",
            color: previewScreen === n ? "#fff" : C.accentDeep,
          }}>Экран {n}</button>
        ))}
      </div>
      <Phone>
        {previewScreen === 1 ? (
          <>
            <Sticker src={data.s1Custom || S1_IMAGES[data.s1Img]} />
            <h3 style={{ color: C.accentDeep, textAlign: "center", margin: "22px 0 18px", fontSize: 18, fontWeight: 700 }}>{data.s1Title}</h3>
            <button style={btnStyle()}>{data.s1Yes}</button>
            <button style={btnStyle(true)}>{data.s1No}</button>
          </>
        ) : (
          <>
            <Sticker emoji={STICKERS_2[data.s2Img]} src={data.s2Custom} />
            <h3 style={{ color: C.accentDeep, textAlign: "center", margin: "22px 0 6px", fontSize: 17, fontWeight: 700 }}>{data.s2Title}</h3>
            <p style={{ color: C.accentDeep, textAlign: "center", fontSize: 13, margin: "0 0 14px" }}>{data.s2Sub}</p>
            <button style={btnStyle()}>{data.s2Btn}</button>
          </>
        )}
      </Phone>
    </div>
  );

  const STEPS = ["Экраны 1–2", "Подтверждение", "Дата и время", "Выбор блюда", "Финал"];

  return (
    <div style={{
      minHeight: "100vh", background: C.bg, fontFamily: "'Segoe UI', system-ui, sans-serif",
      color: C.ink, padding: "28px 16px 60px",
    }}>
      {/* лого */}
      <div style={{ textAlign: "center", marginBottom: 8 }}>
        <div style={{ fontSize: 32, fontWeight: 800, color: C.accent, fontStyle: "italic" }}>Её день</div>
        <div style={{ fontSize: 12, letterSpacing: 3, color: C.accentDeep, fontWeight: 700 }}>ОНЛАЙН-ОТКРЫТКИ</div>
      </div>

      {/* шаги */}
      <div style={{ display: "flex", justifyContent: "center", alignItems: "center", gap: 0, margin: "24px auto", maxWidth: 560 }}>
        {[1, 2, 3, 4, 5].map((n, i) => (
          <React.Fragment key={n}>
            <button onClick={() => setStep(n)} style={{
              width: 34, height: 34, borderRadius: "50%", border: "none", cursor: "pointer",
              fontWeight: 700, fontSize: 15, color: "#fff",
              background: n <= step ? C.accent : C.accentSoft,
            }}>{n}</button>
            {i < 4 && <div style={{ flex: 1, height: 3, background: n < step ? C.accent : C.line }} />}
          </React.Fragment>
        ))}
      </div>

      {/* основная сетка */}
      <div style={{
        maxWidth: 960, margin: "0 auto", display: "grid",
        gridTemplateColumns: "300px 1fr", gap: 32, alignItems: "start",
      }}>
        {/* левая колонка — превью */}
        <div>{step <= 2 ? <Phone12 /> : <Preview />}</div>

        {/* правая колонка — редактор */}
        <div style={{
          background: C.card, borderRadius: 24, padding: 28,
          boxShadow: "0 8px 30px rgba(209,75,124,0.08)",
        }}>
          {/* ШАГ 1 + 2 */}
          {step <= 2 && (
            <>
              <h2 style={{ textAlign: "center", fontSize: 22, margin: "0 0 4px" }}>Настрой первые экраны</h2>
              <p style={{ textAlign: "center", color: C.muted, fontSize: 14, margin: "0 0 24px" }}>
                Тексты и картинки для шагов 1 и 2
              </p>

              <SectionCard title="Экран 1 — приглашение">
                <StickerPicker options={S1_IMAGES} selected={data.s1Img} custom={data.s1Custom}
                  onSelect={(i) => set({ s1Img: i, s1Custom: null })} onUpload={(d) => set({ s1Custom: d })} />
                <Field label="Заголовок" value={data.s1Title} max={300} multiline onChange={(v) => set({ s1Title: v })} />
                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                  <Field label="Кнопка «Да»" value={data.s1Yes} onChange={(v) => set({ s1Yes: v })} />
                  <Field label="Кнопка «Нет»" value={data.s1No} onChange={(v) => set({ s1No: v })} />
                </div>
              </SectionCard>

              <SectionCard title="Экран 2 — подтверждение">
                <StickerPicker options={STICKERS_2} selected={data.s2Img} custom={data.s2Custom}
                  onSelect={(i) => set({ s2Img: i, s2Custom: null })} onUpload={(d) => set({ s2Custom: d })} />
                <Field label="Заголовок" value={data.s2Title} multiline onChange={(v) => set({ s2Title: v })} />
                <Field label="Подзаголовок" value={data.s2Sub} multiline onChange={(v) => set({ s2Sub: v })} />
                <Field label="Кнопка подтверждения" value={data.s2Btn} onChange={(v) => set({ s2Btn: v })} />
              </SectionCard>
            </>
          )}

          {/* ШАГ 3 */}
          {step === 3 && (
            <>
              <h2 style={{ textAlign: "center", fontSize: 22, margin: "0 0 4px" }}>Экран выбора даты и времени</h2>
              <p style={{ textAlign: "center", color: C.accentDeep, fontSize: 14, margin: "0 0 24px" }}>
                Заголовок и кнопка для шага, где приглашённый выбирает дату и время
              </p>
              <StickerPicker options={STICKERS_3} selected={data.s3Img} custom={data.s3Custom}
                onSelect={(i) => set({ s3Img: i, s3Custom: null })} onUpload={(d) => set({ s3Custom: d })} />
              <Field label="Заголовок" value={data.s3Title} multiline onChange={(v) => set({ s3Title: v })} />
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                <label style={{ display: "block", marginBottom: 18 }}>
                  <span style={{ display: "block", fontSize: 15, marginBottom: 6 }}>Дата</span>
                  <input type="date" value={data.date} onChange={(e) => set({ date: e.target.value })}
                    style={{ width: "100%", boxSizing: "border-box", padding: "11px 14px", borderRadius: 14, border: `1.5px solid ${C.fieldLine}`, fontSize: 15 }} />
                </label>
                <label style={{ display: "block", marginBottom: 18 }}>
                  <span style={{ display: "block", fontSize: 15, marginBottom: 6 }}>Время</span>
                  <input type="time" value={data.time} onChange={(e) => set({ time: e.target.value })}
                    style={{ width: "100%", boxSizing: "border-box", padding: "11px 14px", borderRadius: 14, border: `1.5px solid ${C.fieldLine}`, fontSize: 15 }} />
                </label>
              </div>
              <Field label="Текст кнопки" value={data.s3Btn}
                hint="У получателя кнопка активна только после выбора даты и времени"
                onChange={(v) => set({ s3Btn: v })} />
            </>
          )}

          {/* ШАГ 4 */}
          {step === 4 && (
            <>
              <h2 style={{ textAlign: "center", fontSize: 22, margin: "0 0 4px" }}>Настрой экран выбора блюда</h2>
              <p style={{ textAlign: "center", color: C.accentDeep, fontSize: 14, margin: "0 0 24px" }}>От 3 до 6 вариантов</p>
              <Field label="Заголовок" value={data.foodTitle} multiline onChange={(v) => set({ foodTitle: v })} />
              <Field label="Подзаголовок" value={data.foodSub} multiline onChange={(v) => set({ foodSub: v })} />
              {data.foods.map((f, i) => (
                <SectionCard key={i} title={`Блюдо ${i + 1}`} onDelete={data.foods.length > 3 ? () => {
                  const next = data.foods.filter((_, idx) => idx !== i); set({ foods: next });
                } : null}>
                  <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                    <Sticker emoji={f.emoji} src={f.custom} size={40} />
                    <FoodUpload onUpload={(d) => {
                      const next = [...data.foods]; next[i] = { ...next[i], custom: d }; set({ foods: next });
                    }} />
                  </div>
                  <div style={{ marginTop: 12 }}>
                    <Field label="Название" value={f.name} onChange={(v) => {
                      const next = [...data.foods]; next[i] = { ...next[i], name: v }; set({ foods: next });
                    }} />
                  </div>
                </SectionCard>
              ))}
              {data.foods.length < 6 && (
                <button onClick={() => set({ foods: [...data.foods, { name: "Новое блюдо", emoji: "🍽️", custom: null }] })}
                  style={{ width: "100%", padding: 14, borderRadius: 16, border: `1.5px dashed ${C.accent}`, background: "#fff", color: C.accentDeep, fontSize: 15, cursor: "pointer", fontWeight: 600 }}>
                  + Добавить блюдо
                </button>
              )}
            </>
          )}

          {/* ШАГ 5 */}
          {step === 5 && (
            <>
              <h2 style={{ textAlign: "center", fontSize: 22, margin: "0 0 4px" }}>Финальный экран</h2>
              <p style={{ textAlign: "center", color: C.accentDeep, fontSize: 14, margin: "0 0 24px" }}>
                В описании {"{date}"}, {"{time}"} и {"{food}"} автоматически подставят дату, время и блюдо, которые выберет приглашённый
              </p>
              <Field label="Заголовок" value={data.finTitle} max={300} multiline onChange={(v) => set({ finTitle: v })} />
              <Field label="Описание" value={data.finDesc} max={500} multiline onChange={(v) => set({ finDesc: v })} />
              <Field label="Ваш Telegram" value={data.telegram} placeholder="@username"
                hint="Ответы приглашённого придут в Telegram после оплаты. Укажите ник, с которого откроете бота."
                onChange={(v) => set({ telegram: v })} />
              <div style={{ border: `1.5px solid ${C.accentSoft}`, borderRadius: 16, padding: 16, marginTop: 8 }}>
                <div style={{ fontSize: 13, color: C.accentDeep, marginBottom: 8 }}>Пример для получателя:</div>
                <div style={{ fontWeight: 700, color: C.accentDeep, marginBottom: 4 }}>{data.finTitle}</div>
                <div style={{ color: C.ink, fontSize: 14 }}>{finFilled}</div>
              </div>
            </>
          )}

          {/* навигация */}
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 28 }}>
            <button onClick={() => setStep((s) => Math.max(1, s - 1))}
              disabled={step === 1}
              style={{ background: "none", border: "none", color: step === 1 ? C.line : C.ink, fontSize: 15, cursor: step === 1 ? "default" : "pointer" }}>
              ← Назад
            </button>
            {step < 5 ? (
              <button onClick={() => setStep((s) => Math.min(5, s + 1))}
                style={{ padding: "12px 28px", borderRadius: 24, border: "none", color: "#fff", fontSize: 15, fontWeight: 600, cursor: "pointer", background: `linear-gradient(90deg, ${C.accentSoft}, ${C.accent})` }}>
                Далее
              </button>
            ) : (
              <button onClick={() => alert("Приглашение создано! 🎉\n\n(в реальной версии тут переход к оплате/генерации ссылки)")}
                style={{ padding: "12px 28px", borderRadius: 24, border: "none", color: "#fff", fontSize: 15, fontWeight: 600, cursor: "pointer", background: `linear-gradient(90deg, ${C.accent}, ${C.accentDeep})` }}>
                Создать приглашение
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function SectionCard({ title, children, onDelete }) {
  return (
    <div style={{ border: `1.5px solid ${C.line}`, borderRadius: 18, padding: 20, marginBottom: 20 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
        <span style={{ color: C.accentDeep, fontWeight: 600, fontSize: 15 }}>{title}</span>
        {onDelete && <button onClick={onDelete} style={{ background: "none", border: "none", color: C.accent, cursor: "pointer", fontSize: 14 }}>Удалить</button>}
      </div>
      {children}
    </div>
  );
}

function FoodUpload({ onUpload }) {
  const ref = useRef(null);
  return (
    <>
      <button onClick={() => ref.current?.click()}
        style={{ padding: "7px 14px", borderRadius: 12, border: `1.5px solid ${C.accent}`, background: "#fff", color: C.accentDeep, fontSize: 13, cursor: "pointer" }}>
        Загрузить картинку
      </button>
      <input ref={ref} type="file" accept="image/*" hidden onChange={(e) => {
        const f = e.target.files?.[0];
        if (f) { const r = new FileReader(); r.onload = () => onUpload(r.result); r.readAsDataURL(f); }
      }} />
    </>
  );
}